import { useEffect, useRef } from 'react';
import { useSimulationStore } from '../store';

export default function MainArea() {
  const { currentPrice, isRunning, priceHistory } = useSimulationStore();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const isUp = priceHistory[priceHistory.length - 1] >= priceHistory[0];
  const accentColor = isUp ? '#00ff88' : '#ff4d4d';

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;

    const dpr = window.devicePixelRatio || 1;
    const { width, height } = container.getBoundingClientRect();

    // Resize canvas to match container with DPR scaling
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.scale(dpr, dpr);

    const W = width;
    const H = height;
    const PAD = { top: 24, right: 24, bottom: 32, left: 24 };

    // Clear
    ctx.clearRect(0, 0, W, H);

    // --- Background grid ---
    ctx.strokeStyle = 'rgba(255,255,255,0.05)';
    ctx.lineWidth = 1;
    const cols = 8;
    const rows = 5;
    for (let i = 0; i <= cols; i++) {
      const x = PAD.left + (i / cols) * (W - PAD.left - PAD.right);
      ctx.beginPath();
      ctx.moveTo(x, PAD.top);
      ctx.lineTo(x, H - PAD.bottom);
      ctx.stroke();
    }
    for (let i = 0; i <= rows; i++) {
      const y = PAD.top + (i / rows) * (H - PAD.top - PAD.bottom);
      ctx.beginPath();
      ctx.moveTo(PAD.left, y);
      ctx.lineTo(W - PAD.right, y);
      ctx.stroke();
    }

    if (priceHistory.length < 2) return;

    const minPrice = Math.min(...priceHistory);
    const maxPrice = Math.max(...priceHistory);
    const priceRange = maxPrice - minPrice || 1;

    const chartW = W - PAD.left - PAD.right;
    const chartH = H - PAD.top - PAD.bottom;

    const toX = (i: number) => PAD.left + (i / (priceHistory.length - 1)) * chartW;
    const toY = (p: number) => PAD.top + chartH - ((p - minPrice) / priceRange) * chartH;

    // --- Gradient fill under curve ---
    const gradFill = ctx.createLinearGradient(0, PAD.top, 0, H - PAD.bottom);
    gradFill.addColorStop(0, accentColor + '33');   // 20% opacity
    gradFill.addColorStop(1, accentColor + '00');   // 0% opacity

    ctx.beginPath();
    ctx.moveTo(toX(0), toY(priceHistory[0]));

    for (let i = 1; i < priceHistory.length; i++) {
      const x0 = toX(i - 1);
      const y0 = toY(priceHistory[i - 1]);
      const x1 = toX(i);
      const y1 = toY(priceHistory[i]);
      const cpx = (x0 + x1) / 2;
      ctx.quadraticCurveTo(cpx, y0, x1, y1);
    }

    // Close path for fill
    ctx.lineTo(toX(priceHistory.length - 1), H - PAD.bottom);
    ctx.lineTo(toX(0), H - PAD.bottom);
    ctx.closePath();
    ctx.fillStyle = gradFill;
    ctx.fill();

    // --- Glowing bezier line ---
    // Outer glow pass
    ctx.beginPath();
    ctx.moveTo(toX(0), toY(priceHistory[0]));
    for (let i = 1; i < priceHistory.length; i++) {
      const x0 = toX(i - 1);
      const y0 = toY(priceHistory[i - 1]);
      const x1 = toX(i);
      const y1 = toY(priceHistory[i]);
      const cpx = (x0 + x1) / 2;
      ctx.quadraticCurveTo(cpx, y0, x1, y1);
    }
    ctx.strokeStyle = accentColor + '44';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.shadowColor = accentColor;
    ctx.shadowBlur = 20;
    ctx.stroke();

    // Core line pass
    ctx.beginPath();
    ctx.moveTo(toX(0), toY(priceHistory[0]));
    for (let i = 1; i < priceHistory.length; i++) {
      const x0 = toX(i - 1);
      const y0 = toY(priceHistory[i - 1]);
      const x1 = toX(i);
      const y1 = toY(priceHistory[i]);
      const cpx = (x0 + x1) / 2;
      ctx.quadraticCurveTo(cpx, y0, x1, y1);
    }
    ctx.strokeStyle = accentColor;
    ctx.lineWidth = 2;
    ctx.shadowBlur = 12;
    ctx.stroke();

    // Reset shadow
    ctx.shadowBlur = 0;

    // --- Tip dot ---
    const tipX = toX(priceHistory.length - 1);
    const tipY = toY(priceHistory[priceHistory.length - 1]);
    ctx.beginPath();
    ctx.arc(tipX, tipY, 4, 0, Math.PI * 2);
    ctx.fillStyle = accentColor;
    ctx.shadowColor = accentColor;
    ctx.shadowBlur = 16;
    ctx.fill();
    ctx.shadowBlur = 0;

  }, [priceHistory, accentColor]);

  // Handle container resize
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const ro = new ResizeObserver(() => {
      // Trigger redraw by forcing a re-render via a no-op — the priceHistory dep handles it
      // We just need to redraw on resize; call the draw logic directly
      const canvas = canvasRef.current;
      if (!canvas) return;
      canvas.dispatchEvent(new Event('resize-redraw'));
    });
    ro.observe(container);
    return () => ro.disconnect();
  }, []);

  return (
    <main className="flex-1 flex flex-col p-6 min-h-0">
      <div className="w-full h-full bg-[#161b22]/80 backdrop-blur-md border border-white/10 rounded-xl flex flex-col min-h-[400px] overflow-hidden">

        {/* Price overlay */}
        <div className="flex items-center justify-between px-5 pt-4 pb-2 shrink-0">
          <div>
            <p className="text-xs text-white/30 uppercase tracking-widest mb-0.5">Current Price</p>
            <p className={`font-mono text-3xl font-bold ${isUp ? 'text-[#00ff88]' : 'text-[#ff4d4d]'}`}>
              ${currentPrice.toFixed(2)}
            </p>
          </div>
          <div className={`flex items-center gap-2 text-xs font-mono ${isRunning ? 'text-[#00ff88]' : 'text-white/30'}`}>
            <span className={`w-2 h-2 rounded-full ${isRunning ? 'bg-[#00ff88] animate-pulse' : 'bg-white/20'}`} />
            {isRunning ? 'LIVE' : 'IDLE'}
          </div>
        </div>

        {/* Canvas */}
        <div ref={containerRef} className="flex-1 relative min-h-0">
          <canvas
            ref={canvasRef}
            className="absolute inset-0 w-full h-full"
          />
        </div>

      </div>
    </main>
  );
}
